<template>
  <div class="flex-direction-column">
    <div
      class="g-page-container-with-header"
      v-for="battery in sortedBatteryData"
      :key="battery.devid"
    >
      <div class="container-header flex-space-between">
        <span class="title">{{ battery.devdesp }} 电池</span>
        <div class="g-button" @click="handleRefreshRow(battery)">更新</div>
      </div>
      <div class="container-content">
        <div class="g-double-column-layout">
          <div class="column">
            <div
              class="g-kv-pair"
              v-for="(label, key) in section1Labels"
              :key="key"
            >
              <div class="label">{{ label }}</div>
              <div
                class="value"
                :style="
                  key === 'status'
                    ? getStatusTextStyle(getSection1Value(battery, key))
                    : {}
                "
              >
                {{ getSection1Value(battery, key) }}
              </div>
            </div>
          </div>
          <div class="column">
            <div
              class="g-kv-pair"
              v-for="(label, key) in section2Labels"
              :key="key"
            >
              <div class="label">{{ label }}</div>
              <div class="value">{{ getSection2Value(battery, key) }}</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { useCommand } from '@/hooks/useCommand.js'
import { useDataMerge } from '@/hooks/useDataMerge'
import { useTimeFormat } from '@/hooks/useTimeFormat'
const { formatTimestamp } = useTimeFormat()

const store = useWslStore()
const { received, isConnected } = storeToRefs(store)
const { sendGetStatusData } = useCommand(store)

import { useStatus } from '@/hooks/useStatus'
const { getStatusTextStyle } = useStatus()

import { useSortData } from '@/hooks/useSortData'

// 标签定义
const section1Labels = {
  devid: '设备ID',
  devname: '设备名称',
  devtype: '设备类型',
  devdesp: '设备描述',
  status: '状态',
  timestamp: '时间'
}

const section2Labels = {
  voltage: '电池电压',
  current: '电池电流',
  power: '电池电量'
}

// 获取电池数据，兼容13和61命令
const batteryData = useDataMerge(
  computed(() => {
    const data = received.value?.statusData?.batteryDataList
    if (!data || data.length === 0) {
      return [
        {
          devdesp: '暂无'
        }
      ]
    }
    return data
  })
).mergedData

const sortedBatteryData = useSortData(batteryData, {
  key: 'devid',
  type: 'number',
  order: 'asc'
}).sortedData

// 第一组值的获取
const getSection1Value = (item, key) => {
  let value = item[key]

  // 处理时间戳
  if (key === 'timestamp' && value) {
    value = formatTimestamp(value)
  }

  return value === null || value === undefined || value === '' ? '-' : value
}

const getSection2Value = (item, key) => {
  const value = item[key]
  if (value === null || value === undefined || value === '') return '-'

  // 处理数字并添加单位
  const formattedValue = Number(value).toFixed(2)
  const unitMap = {
    voltage: 'V',
    current: 'A',
    power: '%'
  }
  return unitMap[key] ? `${formattedValue}${unitMap[key]}` : formattedValue
}

// 单行刷新处理
const handleRefreshRow = (item) => {
  if (item.devid) {
    sendGetStatusData('battery', item.devid)
  }
}

// 等socket连接后发送13命令获取数据
watch(
  () => isConnected.value,
  (newStatus) => {
    if (newStatus) {
      sendGetStatusData('battery')
    }
  },
  { immediate: true }
)
</script>

<style lang="less" scoped></style>
